import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"论皮斯托亚事务","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/179-论皮斯托亚事务.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/179-论皮斯托亚事务.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/179-论皮斯托亚事务.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"论皮斯托亚事务",tabindex:"-1"},[t("论皮斯托亚事务 "),e("a",{class:"header-anchor",href:"#论皮斯托亚事务","aria-label":'Permalink to "论皮斯托亚事务"'},"​")],-1),e("p",null,"论皮斯托亚事务 让愿意返回皮斯托亚的潘恰蒂奇家族回到该城。就这样事情平息了几天。 但是，后来瓦伦蒂诺的人马来到了我们城门口，执政团顾不上皮斯托亚的 事务，要将部队从那里调出。而已经很大程度上被削弱了的潘恰蒂奇家族 不是自己要走，就是被他人驱赶，后来也离开了皮斯托亚：那是在5月头 几天的事。后来，没过多久，专员们都回到了本城，只在那里留下了两个 主管( rettori), 也没有部队。局面变得比先前更加混乱，其间发生了许 多严重的事件， 一直持续到1501年7月和8月的这任执政团。执政团成员听 说那两个家族试图缔结和约，私下里在接洽，不让执政团成员或主管插 手；于是，执政团成员担心这种事情对本城不利，便开始探听到底是哪个 家族想要议和。发现他们意向已很明确，便委派两位执政团成员和另外两 位顾问团成员去处理此事。又派一个密使到郊外①,另一个则到皮斯托亚 城内，不让这两个家族相互走动。最后，经过派出代表的漫长讨论，在8 月21日达成了两城之间的和约条款。他们又产生了新的专员，这些人于9 月5日出发，从那时起到10月20日， 一直致力于赢得两个家族的支持，并 确保和平，正如和约条款所规定的。这些事情完成后，我们的最高执政团 成员们希望完善和约并护送潘恰蒂奇家族返回皮斯托亚，便派出一名新的 专员，率领部队，正如他们所说的，于10月20日来到皮斯托亚，安置下潘 恰蒂奇家族，并且布置防卫，因为这是维持局面所必需的。事情就是这 样， 一直到了来年的2月23日。后面又发生骚乱的原因则有各种不同的说 法。结果是这样的：主管们告知最高执政团成员们发生了骚乱，并且需要 派出一个专员，执政团成员们立刻委派了托马索 ·托辛吉。此人在上面所 说的2月23日出发，但没有赶上时间，因为他发现潘恰蒂奇家族又被皮斯 托亚人用武力驱逐了。有人受了伤，两位领主和一个步兵队长被杀，这 三个人都是潘恰蒂奇那一派的，还有一些房子被焚烧洗劫。专员们尽力补 救，以防事态进一步扩大。这时，最高执政团成员们希望了解事情的真相",-1),e("p",null,"①当时潘恰蒂奇家族已离开皮斯托亚城，住在郊外。",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
